import { Component, EventEmitter, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AuthService } from '../auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  @Output() loginSuccess = new EventEmitter<void>();

  phoneNumber: string = '';
  otp: string = '';
  otpDigits: string[] = ['', '', '', '', '', ''];
  step: 'PHONE' | 'OTP' = 'PHONE';
  isLoading: boolean = false;
  errorMessage: string = '';

  constructor(private authService: AuthService) {}

  onOtpDigitInput(event: Event, index: number) {
    const input = event.target as HTMLInputElement;
    const value = input.value;

    if (value && !/^\d$/.test(value)) {
      input.value = '';
      this.otpDigits[index] = '';
      return;
    }

    this.otpDigits[index] = value;
    this.otp = this.otpDigits.join('');

    // Auto-focus next input
    if (value && index < 5) {
      const next = input.parentElement?.querySelector(
        `input:nth-child(${index + 2})`
      ) as HTMLInputElement;
      next?.focus();
    }
  }

  onOtpKeydown(event: KeyboardEvent, index: number) {
    const input = event.target as HTMLInputElement;
    if (event.key === 'Backspace' && !input.value && index > 0) {
      const prev = input.parentElement?.querySelector(
        `input:nth-child(${index})`
      ) as HTMLInputElement;
      prev?.focus();
    }
  }

  onOtpPaste(event: ClipboardEvent) {
    event.preventDefault();
    const pasted = event.clipboardData?.getData('text')?.replace(/\D/g, '').slice(0, 6) || '';
    for (let i = 0; i < 6; i++) {
      this.otpDigits[i] = pasted[i] || '';
    }
    this.otp = this.otpDigits.join('');
  }

  sendOtp() {
    if (!this.phoneNumber) return;
    this.isLoading = true;
    this.errorMessage = '';

    this.authService.sendOtp(this.phoneNumber).subscribe({
      next: () => {
        this.isLoading = false;
        this.step = 'OTP';
      },
      error: (err) => {
        this.isLoading = false;
        this.errorMessage = "Erreur d'envoi. Vérifiez le numéro.";
      }
    });
  }

  verifyOtp() {
    if (!this.otp || this.otp.length < 6) return;
    this.isLoading = true;
    this.errorMessage = '';

    this.authService.verifyOtp(this.phoneNumber, this.otp).subscribe({
      next: () => {
        this.isLoading = false;
        this.loginSuccess.emit();
      },
      error: (err) => {
        this.isLoading = false;
        this.errorMessage = "Code incorrect. Réessayez.";
      }
    });
  }

  reset() {
    this.step = 'PHONE';
    this.otp = '';
    this.otpDigits = ['', '', '', '', '', ''];
    this.errorMessage = '';
  }
}
<div class="login-modal">
  <div class="card" style="max-width: 400px; margin: auto; text-align: center; border-top: 5px solid var(--mt-green);">
    <img src="../../logo_materre.png" alt="maTerre Logo" style="height: 60px; margin-bottom: 1rem;">
    <h2>{{ step === 'PHONE' ? 'Bienvenue sur maTerre' : 'Vérification' }}</h2>
    <p style="color: #666; font-size: 0.9rem; margin-bottom: 2rem;">
      {{ step === 'PHONE' 
         ? 'L'arbitre foncier vous demande votre numéro pour sécuriser vos rapports.' 
         : 'Entrez le code à 6 chiffres reçu via WhatsApp ou SMS.' }}
    </p>

    <!-- Step 1: Phone -->
    <div *ngIf="step === 'PHONE'">
      <div style="display: flex; gap: 5px; margin-bottom: 1.5rem;">
        <span style="background: #eee; padding: 12px; border-radius: 4px; font-weight: bold;">+237</span>
        <input type="tel" 
               [(ngModel)]="phoneNumber"
               placeholder="Numéro de téléphone" 
               style="flex: 1; padding: 12px; border: 1px solid #ccc; border-radius: 4px; font-size: 1rem;">
      </div>
      <button (click)="sendOtp()" 
              [disabled]="isLoading || !phoneNumber"
              class="btn-primary" style="width: 100%; font-size: 1.1rem;">
        {{ isLoading ? 'Envoi en cours...' : 'Recevoir mon code' }}
      </button>
      <div style="margin-top: 1rem; font-size: 0.8rem; color: #888;">
        Vérification gratuite via <strong>WhatsApp</strong> ou <strong>SMS</strong>.
      </div>
    </div>

    <!-- Step 2: OTP -->
    <div *ngIf="step === 'OTP'">
      <input type="text" 
             [(ngModel)]="otp"
             maxlength="6"
             placeholder="Code à 6 chiffres" 
             style="width: 100%; padding: 12px; border: 1px solid #ccc; border-radius: 4px; text-align: center; letter-spacing: 5px; font-size: 1.5rem; font-weight: bold; margin-bottom: 1.5rem;">
      
      <button (click)="verifyOtp()" 
              [disabled]="isLoading || otp.length < 6"
              class="btn-primary" style="width: 100%; font-size: 1.1rem;">
        {{ isLoading ? 'Validation...' : 'Se connecter' }}
      </button>

      <div style="margin-top: 1.5rem; display: flex; justify-content: space-between;">
        <button (click)="reset()" style="background: none; border: none; color: #666; text-decoration: underline; cursor: pointer;">Changer de numéro</button>
        <button (click)="sendOtp()" style="background: none; border: none; color: var(--mt-green); font-weight: bold; cursor: pointer;">Renvoyer le code</button>
      </div>
    </div>

    <!-- Error -->
    <p *ngIf="errorMessage" style="color: var(--mt-red); margin-top: 1rem; font-weight: bold;">{{ errorMessage }}</p>
  </div>
</div>
